SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND ((t.Volume_3M_P50*t.Price/ NULLIF(t.Inflation_7, 0))>3600000000.0) AND (t.Risk_Rating <= 5) AND ((t.CF_OA_P0+t.CF_OA_P1+t.CF_OA_P2+t.CF_OA_P3 + t.CF_Invest_P0 + t.CF_Invest_P1+ t.CF_Invest_P2+t.CF_Invest_P3)/(t.OShares*t.Price + t.LtDebt_P0) > 0.055) AND (ABS(t.IntCov_P0) > 1.0) AND (t.NP_P0 > 0) AND (t.NP_P1 > 0) AND (t.PE > 4.8) AND (t.PE < 19.5) AND (t.DY > 0.022) ORDER BY t.ticker, t.time